parameters.jsCode:
const input = $json.body ?? $json;
const amount = Number(input.amount || 0);
const customer = input.customer || {};
const errors = [];

if (!input.rental_id) errors.push('rental_id obrigatorio');
if (!input.user_id) errors.push('user_id obrigatorio');
if (!amount || Number.isNaN(amount) || amount <= 0) errors.push('amount deve ser maior que zero');
if (!customer.name) errors.push('customer.name obrigatorio');
if (!customer.email) errors.push('customer.email obrigatorio');
if (!customer.cpfCnpj) errors.push('customer.cpfCnpj obrigatorio');

if (errors.length) {
  throw new Error(errors.join(' | '));
}

const pad = (value) => String(value).padStart(2, '0');
const plusDays = (days) => {
  const date = new Date();
  date.setDate(date.getDate() + days);
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
};

const dueDate = input.due_date || plusDays(1);
const vehicle = input.vehicle || {};
const externalReference = input.external_reference || `OLI-CAUCAO-${input.rental_id}`;
const description = input.description || `Caucao da reserva ${input.rental_id}${vehicle.plate ? ` - ${vehicle.plate}` : ''}`;

return [{
  json: {
    source: input,
    rental_id: input.rental_id,
    user_id: input.user_id,
    vehicle_id: input.vehicle_id || null,
    amount,
    dueDate,
    billingType: input.billingType || 'UNDEFINED',
    externalReference,
    description,
    provider: input.provider || 'asaas',
    payment_type: input.payment_type || 'deposit',
    customer: {
      name: String(customer.name || '').trim(),
      email: String(customer.email || '').trim(),
      cpfCnpj: String(customer.cpfCnpj || '').replace(/\D/g, ''),
      phone: String(customer.phone || customer.mobilePhone || '').replace(/\D/g, ''),
      mobilePhone: String(customer.phone || customer.mobilePhone || '').replace(/\D/g, ''),
    },
    vehicle,
    escrow: input.escrow || { enabled: true },
  },
}];

const request = $('Normalizar Payload').first().json;
const customer = $json;
if (!customer.id) {
  throw new Error('Asaas nao retornou customer.id');
}

return [{
  json: {
    ...request,
    customerId: customer.id,
    provider_customer_id: customer.id,
    customerResponse: customer,
  },
}];

