parameters.jsCode:
const request = $('Consolidar Cliente').first().json;
const payment = $json;

if (!payment.id) {
  throw new Error('Asaas nao retornou payment.id');
}

const status = String(payment.status || 'PENDING').toUpperCase();
const normalizedStatus = ['RECEIVED', 'CONFIRMED', 'RECEIVED_IN_CASH'].includes(status)
  ? 'confirmed'
  : ['OVERDUE', 'DELETED', 'CANCELLED'].includes(status)
    ? 'failed'
    : 'pending';

return [{
  json: {
    success: true,
    provider: 'asaas',
    payment_type: request.payment_type,
    rental_id: request.rental_id,
    user_id: request.user_id,
    vehicle_id: request.vehicle_id,
    amount: payment.value ?? request.amount,
    status: normalizedStatus,
    raw_status: payment.status || 'PENDING',
    method: 'asaas',
    billingType: payment.billingType || request.billingType,
    id: payment.id,
    provider_payment_id: payment.id,
    provider_customer_id: request.provider_customer_id,
    customer: request.provider_customer_id,
    external_reference: payment.externalReference || request.externalReference,
    reference: payment.externalReference || request.externalReference,
    payment_link: payment.invoiceUrl || payment.bankSlipUrl || null,
    invoice_url: payment.invoiceUrl || null,
    bank_slip_url: payment.bankSlipUrl || null,
    due_date: payment.dueDate || request.dueDate,
    message: request.escrow?.enabled
      ? 'Cobranca de caucao criada na Asaas. Se a conta usada tiver Escrow habilitado, o valor ficara retido ate a liberacao manual.'
      : 'Cobranca de caucao criada na Asaas.',
    escrow: {
      requested: Boolean(request.escrow?.enabled),
      release_condition: request.escrow?.release_condition || null,
      release_checklist: request.escrow?.release_checklist || [],
      note: 'A retencao real depende da conta/subconta usada nesta credencial estar com Conta Escrow habilitada no Asaas.',
    },
    asaas_payment: payment,
  },
}];
